<summary>♻️ Example refactor to shared utilities</summary>

Create `scripts/lib/git-utils.mjs`:

```js
import { spawnSync } from 'node:child_process';

export const runGit = (args) => {
  const result = spawnSync('git', args, {
    encoding: 'utf8',
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  if (result.status !== 0) {
    return null;
  }

  return result.stdout.trim();
};

export const resolveBase = () => {
  const mainBase = runGit(['merge-base', 'HEAD', 'origin/main']);
  if (mainBase) return mainBase;

  const masterBase = runGit(['merge-base', 'HEAD', 'origin/master']);
  if (masterBase) return masterBase;

  const previousCommit = runGit(['rev-parse', 'HEAD~1']);
  if (previousCommit) return previousCommit;

  return 'HEAD';
};

export const listChangedFiles = (base) => {
  const committed = runGit([
    'diff',
    '--name-only',
    '--diff-filter=ACMR',
    `${base}...HEAD`,
  ]);
  const unstaged = runGit(['diff', '--name-only', '--diff-filter=ACMR']);

  return new Set(
    [...(committed?.split('\n') ?? []), ...(unstaged?.split('\n') ?? [])]
      .map((file) => file.trim())
      .filter(Boolean)
  );
};
```

Then import in both scripts:

```js
import { resolveBase, listChangedFiles } from './lib/git-utils.mjs';
```

</details>

